import java.io.*;import java.util.*;class Employee implements Serializable{int employeeId;String name,department;double salary;Employee(int i,String n,String d,double s){employeeId=i;name=n;department=d;salary=s;}}public class EmployeeSkillAssignment{static void team(int[]a,int i,int t,List<Integer>l){if(t==0){System.out.println(l);return;}if(i==a.length||t<0)return;l.add(a[i]);team(a,i+1,t-a[i],l);l.remove(l.size()-1);team(a,i+1,t,l);}public static void main(String[]args)throws Exception{Scanner sc=new Scanner(System.in);Employee e=new Employee(sc.nextInt(),sc.next(),sc.next(),sc.nextDouble());ObjectOutputStream o=new ObjectOutputStream(new FileOutputStream("employee.ser"));o.writeObject(e);o.close();ObjectInputStream in=new ObjectInputStream(new FileInputStream("employee.ser"));Employee r=(Employee)in.readObject();System.out.println(r.employeeId+" "+r.name+" "+r.department+" "+r.salary);team(new int[]{2,3,5,6,8},0,10,new ArrayList<>());}}